+
+/// Simulation time in milliseconds
+pub type SimTime = f64;
+
+/// Spike event with timestamp
+#[derive(Debug, Clone, Copy, PartialEq)]
+pub struct Spike {
+    /// Neuron ID that fired
+    pub neuron_id: usize,
+    /// Time of spike in simulation time
+    pub time: SimTime,
+}
