+    pub fn apply_reward(&mut self, reward: f64) {
+        for weights in &mut self.feedforward_weights {
+            weights.apply_reward(reward);
+        }
+        for weights in &mut self.recurrent_weights {
+            if let Some(w) = weights {
+                w.apply_reward(reward);
+            }
+        }
+    }
