+            for ((pre, post), synapse) in recurrent.iter() {
+                if *pre < vertices.len() && *post < vertices.len() {
+                    let u = vertices[*pre];
+                    let v = vertices[*post];
+                    if graph.has_edge(u, v) {
+                        let _ = graph.update_edge_weight(u, v, synapse.weight);
+                    }
+                }
+            }
+        }
+    }
+}
