+fn rand_weight() -> f64 {
+    (rand_u64() as f64) / (u64::MAX as f64) * 0.5 + 0.25
+}
+
+fn rand_bool(p: f64) -> bool {
+    (rand_u64() as f64) / (u64::MAX as f64) < p
